347→DEFINE FUNCTION fn::entity_search_workspace($q: string, $limit: int, $workspace: record<workspace>) {
348→  LET $query = string::lowercase(string::trim($q));
349→  LET $safe_limit = math::min([math::max([$limit, 1]), 100]);
350→  LET $workspace_conversations = SELECT VALUE id FROM conversation WHERE workspace = $workspace;
351→  LET $workspace_messages = SELECT VALUE id FROM message WHERE conversation IN $workspace_conversations;
352→  LET $workspace_commits = SELECT VALUE id FROM git_commit WHERE workspace = $workspace;
353→
354→  LET $task_rows = SELECT
355→    id,
356→    "task" AS kind,
357→    title AS text,
358→    extraction_confidence AS confidence,
359→    source_message AS sourceMessage,
360→    priority,
361→    created_at
362→  FROM task
363→  WHERE (
364→      (source_message != NONE AND source_message IN $workspace_messages)
365→      OR (source_commit != NONE AND source_commit IN $workspace_commits)
366→    )
367→    AND extraction_confidence != NONE
368→    AND string::contains(string::lowercase(title), $query)
369→  ORDER BY created_at DESC
370→  LIMIT $safe_limit;
371→
372→  LET $decision_rows = SELECT
373→    id,
374→    "decision" AS kind,
375→    summary AS text,
376→    extraction_confidence AS confidence,
377→    source_message AS sourceMessage,
378→    priority,
379→    created_at
380→  FROM decision
381→  WHERE (
382→      (source_message != NONE AND source_message IN $workspace_messages)
383→      OR (source_commit != NONE AND source_commit IN $workspace_commits)
384→    )
385→    AND extraction_confidence != NONE
386→    AND string::contains(string::lowercase(summary), $query)
387→  ORDER BY created_at DESC
388→  LIMIT $safe_limit;
389→
390→  LET $question_rows = SELECT
391→    id,
392→    "question" AS kind,
393→    text AS text,
394→    extraction_confidence AS confidence,
395→    source_message AS sourceMessage,
396→    priority,
397→    created_at
398→  FROM question
399→  WHERE (
400→      (source_message != NONE AND source_message IN $workspace_messages)
401→      OR (source_commit != NONE AND source_commit IN $workspace_commits)
402→    )
403→    AND extraction_confidence != NONE
404→    AND string::contains(string::lowercase(text), $query)
405→  ORDER BY created_at DESC
406→  LIMIT $safe_limit;
407→
408→  RETURN array::flatten([$task_rows, $decision_rows, $question_rows]);
409→};
