433→    AND id IN $project_entity_ids
434→    AND string::contains(string::lowercase(title), $query)
435→  ORDER BY created_at DESC
436→  LIMIT $safe_limit;
437→
438→  LET $decision_rows = SELECT
439→    id,
440→    "decision" AS kind,
441→    summary AS text,
442→    extraction_confidence AS confidence,
443→    source_message AS sourceMessage,
444→    priority,
