450→    )
451→    AND extraction_confidence != NONE
452→    AND id IN $project_entity_ids
453→    AND string::contains(string::lowercase(summary), $query)
454→  ORDER BY created_at DESC
455→  LIMIT $safe_limit;
456→
457→  LET $question_rows = SELECT
458→    id,
