467→      (source_message != NONE AND source_message IN $workspace_messages)
468→      OR (source_commit != NONE AND source_commit IN $workspace_commits)
469→    )
470→    AND extraction_confidence != NONE
471→    AND id IN $project_entity_ids
472→    AND string::contains(string::lowercase(text), $query)
473→  ORDER BY created_at DESC
474→  LIMIT $safe_limit;
475→
476→  RETURN array::flatten([$task_rows, $decision_rows, $question_rows]);
