479→DEFINE FUNCTION fn::conversation_recent($conversation: record<conversation>, $limit: int) {
480→  LET $safe_limit = math::min([math::max([$limit, 1]), 50]);
481→  RETURN SELECT id, role, text, createdAt
482→  FROM message
483→  WHERE conversation = $conversation
484→  ORDER BY createdAt DESC
485→  LIMIT $safe_limit;
486→};
