488→DEFINE FUNCTION fn::entity_neighbors($entity: record) {
489→  RETURN SELECT
490→    ->entity_relation->(workspace, project, person, feature, task, decision, question) AS outgoing,
491→    <-entity_relation<-(workspace, project, person, feature, task, decision, question) AS incoming
492→  FROM $entity;
493→};
