 17→type EntityActionTable = GraphEntityTable | "observation";
 18→
 19→export function createEntityActionsHandler(
 20→  deps: ServerDependencies,
 21→): (entityId: string, request: Request) => Promise<Response> {
 22→  return (entityId: string, request: Request) => handleEntityAction(deps, entityId, request);
 23→}
 24→
 25→async function handleEntityAction(
 26→  deps: ServerDependencies,
 27→  entityId: string,
 28→  request: Request,
 29→): Promise<Response> {
 30→  let body: EntityActionRequest;
 31→  try {
 32→    body = await request.json() as EntityActionRequest;
 33→  } catch {
 34→    return jsonError("invalid JSON body", 400);
 35→  }
 36→
 37→  if (!body.action || !["confirm", "override", "complete", "set_priority", "acknowledge", "resolve"].includes(body.action)) {
 38→    return jsonError("action must be one of: confirm, override, complete, set_priority, acknowledge, resolve", 400);
 39→  }
 40→
 41→  const url = new URL(request.url);
 42→  const workspaceId = url.searchParams.get("workspaceId")?.trim();
 43→  if (!workspaceId) {
 44→    return jsonError("workspaceId is required", 400);
 45→  }
 46→
 47→  let workspaceRecord;
 48→  try {
 49→    workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
 50→  } catch (error) {
 51→    if (error instanceof HttpError) {
 52→      return jsonError(error.message, error.status);
 53→    }
 54→    logError("entity.action.workspace_resolve.failed", "Failed to resolve workspace", error, { workspaceId });
 55→    return jsonError("failed to resolve workspace", 500);
 56→  }
 57→
 58→  try {
 59→    const entityTables: EntityActionTable[] = ["workspace", "project", "person", "feature", "task", "decision", "question", "observation"];
 60→    const entityRecord = parseRecordIdString(entityId, entityTables);
 61→
 62→    const table = entityRecord.table.name;
 63→    const now = new Date();
 64→
 65→    // Observation actions bypass the standard workspace scope check
 66→    // because observations have their own workspace field (not graph edges).
 67→    if (table === "observation") {
 68→      if (body.action === "acknowledge") {
 69→        await acknowledgeObservation({
 70→          surreal: deps.surreal,
 71→          workspaceRecord,
 72→          observationRecord: entityRecord as RecordId<"observation", string>,
 73→          now,
 74→        });
 75→        logInfo("entity.action.acknowledge", "Observation acknowledged", { workspaceId, entityId });
 76→        return jsonResponse({ status: "acknowledged" }, 200);
 77→      }
 78→
 79→      if (body.action === "resolve") {
 80→        await resolveObservation({
 81→          surreal: deps.surreal,
 82→          workspaceRecord,
 83→          observationRecord: entityRecord as RecordId<"observation", string>,
 84→          now,
 85→        });
 86→        logInfo("entity.action.resolve", "Observation resolved", { workspaceId, entityId });
 87→        return jsonResponse({ status: "resolved" }, 200);
 88→      }
 89→
 90→      return jsonError(`action '${body.action}' is not valid for entity type 'observation'`, 400);
 91→    }
 92→
 93→    const scoped = await isEntityInWorkspace(deps.surreal, workspaceRecord, entityRecord as RecordId<GraphEntityTable, string>);
 94→    if (!scoped) {
 95→      return jsonError("entity is outside the current workspace scope", 403);
 96→    }
 97→
 98→    if (body.action === "confirm" && table === "decision") {
 99→      const [decisionRows] = await deps.surreal
100→        .query<[Array<{ summary: string }>]>(
101→          "SELECT summary FROM $record LIMIT 1;",
102→          { record: entityRecord },
103→        )
104→        .collect<[Array<{ summary: string }>]>();
105→      const decisionSummary = decisionRows[0]?.summary ?? entityId;
106→
107→      await confirmDecisionRecord({
108→        surreal: deps.surreal,
109→        decisionRecord: entityRecord as RecordId<"decision", string>,
110→        confirmedAt: now,
111→        notes: body.notes,
112→      });
113→
114→      void fireDescriptionUpdates({
115→        surreal: deps.surreal,
116→        extractionModel: deps.extractionModel,
117→        trigger: {
118→          kind: "decision_confirmed",
119→          entity: entityRecord,
120→          summary: `Decision confirmed: ${decisionSummary}`,
121→        },
122→      }).catch(() => undefined);
123→
124→      logInfo("entity.action.confirm", "Decision confirmed", { workspaceId, entityId });
125→      return jsonResponse({ status: "confirmed" }, 200);
126→    }
127→
128→    if (body.action === "override" && table === "decision") {
129→      if (!body.newSummary) {
130→        return jsonError("newSummary is required for override action", 400);
131→      }
132→      await deps.surreal.update(entityRecord as RecordId<"decision", string>).merge({
133→        summary: body.newSummary,
134→        status: "overridden",
135→        updated_at: now,
136→        ...(body.notes ? { override_notes: body.notes } : {}),
137→      });
138→      logInfo("entity.action.override", "Decision overridden", { workspaceId, entityId });
139→      return jsonResponse({ status: "overridden" }, 200);
140→    }
141→
142→    if (body.action === "complete" && table === "feature") {
143→      const [featureRows] = await deps.surreal
144→        .query<[Array<{ name: string }>]>(
145→          "SELECT name FROM $record LIMIT 1;",
146→          { record: entityRecord },
147→        )
148→        .collect<[Array<{ name: string }>]>();
149→      const featureName = featureRows[0]?.name ?? entityId;
150→
151→      await deps.surreal.update(entityRecord as RecordId<"feature", string>).merge({
152→        status: "done",
153→        updated_at: now,
154→      });
155→
156→      void fireDescriptionUpdates({
157→        surreal: deps.surreal,
158→        extractionModel: deps.extractionModel,
159→        trigger: {
160→          kind: "feature_completed",
161→          entity: entityRecord,
162→          summary: `Feature completed: ${featureName}`,
163→        },
164→      }).catch(() => undefined);
165→
166→      logInfo("entity.action.complete", "Feature completed", { workspaceId, entityId });
167→      return jsonResponse({ status: "completed" }, 200);
168→    }
169→
170→    if (body.action === "complete" && table === "task") {
171→      const [taskRows] = await deps.surreal
172→        .query<[Array<{ title: string }>]>(
173→          "SELECT title FROM $record LIMIT 1;",
174→          { record: entityRecord },
175→        )
176→        .collect<[Array<{ title: string }>]>();
177→      const taskTitle = taskRows[0]?.title ?? entityId;
178→
179→      await deps.surreal.update(entityRecord as RecordId<"task", string>).merge({
180→        status: "done",
181→        completed_at: now,
182→        updated_at: now,
183→      });
184→
185→      void fireDescriptionUpdates({
186→        surreal: deps.surreal,
187→        extractionModel: deps.extractionModel,
188→        trigger: {
189→          kind: "task_completed",
190→          entity: entityRecord,
191→          summary: `Task completed: ${taskTitle}`,
192→        },
193→      }).catch(() => undefined);
194→
195→      logInfo("entity.action.complete", "Task completed", { workspaceId, entityId });
196→      return jsonResponse({ status: "completed" }, 200);
197→    }
198→
199→    if (body.action === "set_priority" && (table === "task" || table === "decision" || table === "question")) {
200→      if (!body.priority || !(ENTITY_PRIORITIES as readonly string[]).includes(body.priority)) {
201→        return jsonError("priority must be one of: low, medium, high, critical", 400);
202→      }
203→      await deps.surreal.update(entityRecord).merge({
204→        priority: body.priority,
205→        updated_at: now,
206→      });
207→      logInfo("entity.action.set_priority", "Priority updated", { workspaceId, entityId, priority: body.priority });
208→      return jsonResponse({ status: "priority_updated", priority: body.priority }, 200);
209→    }
210→
211→    return jsonError(`action '${body.action}' is not valid for entity type '${table}'`, 400);
212→  } catch (error) {
213→    logError("entity.action.failed", "Entity action failed", error, {
214→      workspaceId,
215→      entityId,
216→      action: body.action,
217→    });
218→    const message = error instanceof Error ? error.message : "entity action failed";
219→    return jsonError(message, 500);
220→  }
221→}
