 45→    workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
 46→  } catch (error) {
 47→    if (error instanceof HttpError) {
 48→      logWarn("feed.workspace_resolve.http_error", "Feed workspace resolve failed", {
 49→        workspaceId,
 50→        statusCode: error.status,
 51→      });
 52→      return jsonError(error.message, error.status);
 53→    }
 54→    logError("feed.workspace_resolve.failed", "Feed workspace resolve failed", error, { workspaceId });
 55→    return jsonError("failed to resolve workspace", 500);
 56→  }
 57→
 58→  try {
 59→    const queryInput = { surreal: deps.surreal, workspaceRecord, limit: FEED_ITEM_LIMIT };
 60→
 61→    const [
 62→      provisionalDecisions,
 63→      conflicts,
 64→      blockingQuestions,
 65→      lowConfidenceDecisions,
 66→      blockedTasks,
 67→      observations,
 68→      staleTasks,
 69→      recentlyCompleted,
 70→      recentExtractions,
 71→    ] = await Promise.all([
 72→      listProvisionalDecisions(queryInput),
 73→      listWorkspaceConflicts(queryInput),
 74→      listBlockingQuestions(queryInput),
 75→      listLowConfidenceDecisions({ ...queryInput, confidenceThreshold: LOW_CONFIDENCE_THRESHOLD }),
 76→      listBlockedTasks(queryInput),
 77→      listWorkspaceOpenObservations({ surreal: deps.surreal, workspaceRecord, limit: FEED_ITEM_LIMIT }),
 78→      listStaleTasks({ ...queryInput, staleDays: STALE_DAYS }),
 79→      listRecentlyCompletedItems({ ...queryInput, recentDays: RECENT_COMPLETED_DAYS }),
 80→      listRecentExtractions(queryInput),
 81→    ]);
 82→
 83→    const blocking: GovernanceFeedItem[] = [];
 84→    const review: GovernanceFeedItem[] = [];
 85→    const awareness: GovernanceFeedItem[] = [];
 86→
 87→    // Blocking: provisional decisions
 88→    for (const row of provisionalDecisions) {
 89→      const entityId = row.id.id as string;
 90→      blocking.push({
 91→        id: `decision:${entityId}:${row.status}`,
 92→        tier: "blocking",
 93→        entityId,
 94→        entityKind: "decision",
 95→        entityName: row.summary,
 96→        reason: `${capitalize(row.status)} decision awaiting confirmation`,
 97→        status: row.status,
 98→        ...(row.project ? { project: row.project } : {}),
 99→        ...(row.category ? { category: row.category as EntityCategory } : {}),
100→        ...(row.priority ? { priority: row.priority as EntityPriority } : {}),
101→        createdAt: toIsoString(row.created_at),
102→        actions: decisionActions(),
103→      });
104→    }
105→
106→    // Blocking: conflicts
107→    for (const row of conflicts) {
108→      blocking.push({
109→        id: `conflict:${row.edgeId}`,
110→        tier: "blocking",
111→        entityId: row.fromRecord.id as string,
112→        entityKind: row.fromKind as EntityKind,
113→        entityName: row.fromName,
114→        reason: row.description ?? `Conflicts with ${row.toName}`,
115→        status: "conflict",
116→        ...(row.severity ? { severity: row.severity as ObservationSeverity } : {}),
117→        createdAt: row.detectedAt,
118→        actions: conflictActions(),
119→        conflictTarget: {
120→          entityId: row.toRecord.id as string,
121→          entityKind: row.toKind as EntityKind,
122→          entityName: row.toName,
123→        },
124→      });
125→    }
126→
127→    // Blocking: high/critical questions
128→    for (const row of blockingQuestions) {
129→      const entityId = row.id.id as string;
130→      blocking.push({
131→        id: `question:${entityId}:blocking`,
132→        tier: "blocking",
133→        entityId,
134→        entityKind: "question",
135→        entityName: row.text,
136→        reason: `${capitalize(row.priority)} priority open question`,
137→        status: row.status,
138→        ...(row.project ? { project: row.project } : {}),
139→        ...(row.category ? { category: row.category as EntityCategory } : {}),
140→        priority: row.priority as EntityPriority,
141→        createdAt: toIsoString(row.created_at),
142→        actions: questionActions(),
143→      });
144→    }
145→
146→    // Review: low confidence decisions
147→    for (const row of lowConfidenceDecisions) {
148→      const entityId = row.id.id as string;
149→      review.push({
150→        id: `decision:${entityId}:low_confidence`,
151→        tier: "review",
152→        entityId,
153→        entityKind: "decision",
154→        entityName: row.summary,
155→        reason: `Low confidence inferred decision (${Math.round(row.extraction_confidence * 100)}%)`,
156→        status: row.status,
157→        ...(row.project ? { project: row.project } : {}),
158→        ...(row.category ? { category: row.category as EntityCategory } : {}),
159→        ...(row.priority ? { priority: row.priority as EntityPriority } : {}),
160→        createdAt: toIsoString(row.created_at),
161→        actions: decisionActions(),
162→      });
163→    }
164→
165→    // Review: blocked tasks
166→    for (const row of blockedTasks) {
167→      const entityId = row.id.id as string;
168→      review.push({
169→        id: `task:${entityId}:blocked`,
170→        tier: "review",
171→        entityId,
172→        entityKind: "task",
173→        entityName: row.title,
174→        reason: "Task is blocked",
175→        status: row.status,
176→        ...(row.project ? { project: row.project } : {}),
177→        ...(row.category ? { category: row.category as EntityCategory } : {}),
178→        ...(row.priority ? { priority: row.priority as EntityPriority } : {}),
179→        createdAt: toIsoString(row.created_at),
180→        actions: blockedTaskActions(),
181→      });
182→    }
183→
184→    // Review + Awareness: observations (warning = review, info = awareness)
185→    for (const obs of observations) {
186→      const tier = obs.severity === "info" ? "awareness" : "review";
187→      const item: GovernanceFeedItem = {
188→        id: `observation:${obs.id}:${obs.severity}`,
189→        tier,
190→        entityId: obs.id,
191→        entityKind: "observation",
192→        entityName: obs.text,
193→        reason: `${capitalize(obs.severity)} observation from ${obs.sourceAgent}`,
194→        status: obs.status,
195→        ...(obs.category ? { category: obs.category } : {}),
196→        severity: obs.severity,
197→        createdAt: obs.createdAt,
198→        actions: observationActions(obs.status),
199→      };
200→
201→      if (tier === "review") {
202→        review.push(item);
203→      } else {
204→        awareness.push(item);
205→      }
206→    }
207→
208→    // Awareness: stale tasks
209→    for (const row of staleTasks) {
210→      const entityId = row.id.id as string;
211→      awareness.push({
212→        id: `task:${entityId}:stale`,
213→        tier: "awareness",
214→        entityId,
215→        entityKind: "task",
216→        entityName: row.title,
217→        reason: `Task open for over ${STALE_DAYS} days`,
218→        status: row.status,
219→        ...(row.project ? { project: row.project } : {}),
220→        ...(row.category ? { category: row.category as EntityCategory } : {}),
221→        ...(row.priority ? { priority: row.priority as EntityPriority } : {}),
222→        createdAt: toIsoString(row.created_at),
223→        actions: staleTaskActions(),
224→      });
225→    }
226→
227→    // Awareness: recently completed
228→    for (const row of recentlyCompleted) {
229→      const entityId = row.id.id as string;
230→      awareness.push({
231→        id: `${row.kind}:${entityId}:completed`,
232→        tier: "awareness",
233→        entityId,
234→        entityKind: row.kind as EntityKind,
235→        entityName: row.name,
236→        reason: `Recently completed ${row.kind}`,
237→        status: row.status,
238→        ...(row.project ? { project: row.project } : {}),
239→        ...(row.category ? { category: row.category as EntityCategory } : {}),
240→        createdAt: toIsoString(row.updated_at),
241→        actions: [],
242→      });
243→    }
244→
245→    // Awareness: recent extractions
246→    for (const row of recentExtractions) {
247→      awareness.push({
248→        id: `extraction:${row.edgeId}`,
249→        tier: "awareness",
250→        entityId: row.entityId,
251→        entityKind: row.entityKind as EntityKind,
252→        entityName: row.entityName,
253→        reason: `Extracted from ${row.sourceKind.replace("_", " ")}`,
254→        status: "extracted",
255→        createdAt: row.extractedAt,
256→        actions: [],
257→      });
258→    }
259→
260→    const payload: GovernanceFeedResponse = {
261→      blocking,
262→      review,
263→      awareness,
264→      updatedAt: new Date().toISOString(),
265→    };
266→
267→    logInfo("feed.completed", "Governance feed request completed", {
268→      workspaceId,
269→      blockingCount: blocking.length,
270→      reviewCount: review.length,
271→      awarenessCount: awareness.length,
272→      durationMs: elapsedMs(startedAt),
273→    });
274→
275→    return jsonResponse(payload, 200);
276→  } catch (error) {
277→    logError("feed.failed", "Governance feed request failed", error, { workspaceId });
278→    const message = error instanceof Error ? error.message : "feed request failed";
279→    return jsonError(message, 500);
280→  }
281→}
