283→// --- Action button builders ---
284→
285→function decisionActions(): GovernanceFeedAction[] {
286→  return [
287→    { action: "confirm", label: "Confirm" },
288→    { action: "override", label: "Override" },
289→    { action: "discuss", label: "Discuss" },
290→  ];
291→}
292→
293→function conflictActions(): GovernanceFeedAction[] {
294→  return [
295→    { action: "acknowledge", label: "Acknowledge" },
296→    { action: "resolve", label: "Resolve" },
297→    { action: "discuss", label: "Discuss" },
298→  ];
299→}
300→
301→function questionActions(): GovernanceFeedAction[] {
302→  return [
303→    { action: "resolve", label: "Resolve" },
304→    { action: "discuss", label: "Discuss" },
305→  ];
306→}
307→
308→function observationActions(status: string): GovernanceFeedAction[] {
309→  if (status === "acknowledged") {
310→    return [
311→      { action: "resolve", label: "Resolve" },
312→    ];
313→  }
314→  return [
315→    { action: "acknowledge", label: "Acknowledge" },
316→    { action: "resolve", label: "Resolve" },
317→  ];
318→}
319→
320→function blockedTaskActions(): GovernanceFeedAction[] {
321→  return [
322→    { action: "complete", label: "Complete" },
323→    { action: "discuss", label: "Discuss" },
324→  ];
325→}
326→
327→function staleTaskActions(): GovernanceFeedAction[] {
328→  return [
329→    { action: "complete", label: "Complete" },
330→    { action: "discuss", label: "Discuss" },
331→  ];
332→}
333→
334→function capitalize(value: string): string {
335→  if (value.length === 0) return value;
336→  return value.charAt(0).toUpperCase() + value.slice(1);
337→}
