 57→export type ProvisionalDecisionRow = {
 58→  id: RecordId<"decision", string>;
 59→  summary: string;
 60→  status: string;
 61→  priority?: string;
 62→  category?: string;
 63→  created_at: string | Date;
 64→  project?: string; // resolved after query
