 67→export async function listProvisionalDecisions(
 68→  input: WorkspaceQueryInput,
 69→): Promise<ProvisionalDecisionRow[]> {
 70→  const projects = await getWorkspaceProjectRows(input.surreal, input.workspaceRecord);
 71→  const projectRecords = projects.map((p) => p.id);
 72→  const projectById = new Map(projects.map((p) => [toRecordIdString(p.id), p.name]));
 73→
 74→  const [rows] = await input.surreal
 75→    .query<[
 76→      Array<{
 77→        id: RecordId<"decision", string>;
 78→        summary: string;
 79→        status: string;
 80→        priority?: string;
 81→        category?: string;
 82→        created_at: string | Date;
 83→      }>,
 84→    ]>(
 85→      [
 86→        "SELECT id, summary, status, priority, category, created_at",
 87→        "FROM decision",
 88→        "WHERE status IN ['provisional', 'proposed', 'extracted']",
 89→        `AND ${buildWorkspaceScopeClause("decision")}`,
 90→        "ORDER BY created_at DESC",
 91→        "LIMIT $limit;",
 92→      ].join(" "),
 93→      {
 94→        workspace: input.workspaceRecord,
 95→        projects: projectRecords,
 96→        limit: input.limit,
 97→      },
 98→    )
 99→    .collect<[
100→      Array<{
101→        id: RecordId<"decision", string>;
102→        summary: string;
103→        status: string;
104→        priority?: string;
105→        category?: string;
106→        created_at: string | Date;
107→      }>,
108→    ]>();
109→
110→  const results: ProvisionalDecisionRow[] = [];
111→
112→  for (const row of rows) {
113→    const [projectRows] = await input.surreal
114→      .query<[Array<RecordId<"project", string>>]>(
115→        "SELECT VALUE out FROM belongs_to WHERE `in` = $decision AND out IN $projects LIMIT 1;",
116→        { decision: row.id, projects: projectRecords },
117→      )
118→      .collect<[Array<RecordId<"project", string>>]>();
119→
120→    const project = projectRows[0] ? projectById.get(toRecordIdString(projectRows[0])) : undefined;
121→
122→    results.push({
123→      id: row.id,
124→      summary: row.summary,
125→      status: row.status,
126→      ...(row.priority ? { priority: row.priority } : {}),
127→      ...(row.category ? { category: row.category } : {}),
128→      created_at: row.created_at,
129→      ...(project ? { project } : {}),
130→    });
131→  }
132→
133→  return results;
134→}
