149→export async function listWorkspaceConflicts(input: WorkspaceQueryInput): Promise<ConflictRow[]> {
150→  const [rows] = await input.surreal
151→    .query<[
152→      Array<{
153→        id: RecordId<"conflicts_with", string>;
154→        in: RecordId<"decision" | "feature", string>;
155→        out: RecordId<"decision" | "feature", string>;
156→        description?: string;
157→        severity?: string;
158→        detected_at?: string | Date;
159→      }>,
160→    ]>(
161→      [
162→        "SELECT id, `in`, out, description, severity, detected_at",
163→        "FROM conflicts_with",
164→        "WHERE `in` IN (",
165→        "  SELECT VALUE `in` FROM belongs_to",
166→        "  WHERE out IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace)",
167→        ")",
168→        "OR out IN (",
169→        "  SELECT VALUE `in` FROM belongs_to",
170→        "  WHERE out IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace)",
171→        ")",
172→        "ORDER BY detected_at DESC",
173→        "LIMIT $limit;",
174→      ].join(" "),
175→      { workspace: input.workspaceRecord, limit: input.limit },
176→    )
177→    .collect<[
178→      Array<{
179→        id: RecordId<"conflicts_with", string>;
180→        in: RecordId<"decision" | "feature", string>;
181→        out: RecordId<"decision" | "feature", string>;
182→        description?: string;
183→        severity?: string;
184→        detected_at?: string | Date;
185→      }>,
186→    ]>();
187→
188→  const results: ConflictRow[] = [];
189→
190→  for (const row of rows) {
191→    const fromKind = row.in.table.name as "decision" | "feature";
192→    const toKind = row.out.table.name as "decision" | "feature";
193→
194→    const fromName = await readEntityNameByTable(input.surreal, row.in, fromKind);
195→    const toName = await readEntityNameByTable(input.surreal, row.out, toKind);
196→
197→    if (!fromName || !toName) continue;
198→
199→    results.push({
200→      edgeId: toRecordIdString(row.id),
201→      fromRecord: row.in,
202→      fromName,
203→      fromKind,
204→      toRecord: row.out,
205→      toName,
206→      toKind,
207→      ...(row.description ? { description: row.description } : {}),
208→      ...(row.severity ? { severity: row.severity } : {}),
209→      detectedAt: row.detected_at ? toIso(row.detected_at) : new Date().toISOString(),
210→    });
211→  }
212→
213→  return results;
214→}
