706→export async function listRecentExtractions(input: WorkspaceQueryInput): Promise<RecentExtractionRow[]> {
707→  const [rows] = await input.surreal
708→    .query<[
709→      Array<{
710→        id: RecordId<"extraction_relation", string>;
711→        in: RecordId<"message" | "document_chunk" | "git_commit", string>;
712→        out: RecordId<string, string>;
713→        confidence: number;
714→        extracted_at: string | Date;
715→      }>,
716→    ]>(
717→      [
718→        "SELECT id, `in`, out, confidence, extracted_at",
719→        "FROM extraction_relation",
720→        "WHERE `in` IN (",
721→        "  SELECT VALUE id FROM message",
722→        "  WHERE conversation IN (SELECT VALUE id FROM conversation WHERE workspace = $workspace)",
723→        ")",
724→        "OR `in` IN (SELECT VALUE id FROM document_chunk WHERE workspace = $workspace)",
725→        "OR `in` IN (SELECT VALUE id FROM git_commit WHERE workspace = $workspace)",
726→        "ORDER BY extracted_at DESC",
727→        "LIMIT $limit;",
728→      ].join(" "),
729→      { workspace: input.workspaceRecord, limit: input.limit },
730→    )
731→    .collect<[
732→      Array<{
733→        id: RecordId<"extraction_relation", string>;
734→        in: RecordId<"message" | "document_chunk" | "git_commit", string>;
735→        out: RecordId<string, string>;
736→        confidence: number;
737→        extracted_at: string | Date;
738→      }>,
739→    ]>();
740→
741→  const results: RecentExtractionRow[] = [];
742→
743→  for (const row of rows) {
744→    const entityKind = row.out.table.name;
745→    const entityName = await readEntityNameByTable(input.surreal, row.out, entityKind);
746→    if (!entityName) continue;
747→
748→    const sourceKind = row.in.table.name === "document_chunk"
749→      ? "document_chunk"
750→      : row.in.table.name === "git_commit"
751→        ? "git_commit"
752→        : "message";
753→
754→    results.push({
755→      edgeId: toRecordIdString(row.id),
756→      sourceKind: sourceKind as "message" | "document_chunk" | "git_commit",
757→      sourceId: toRecordIdString(row.in),
758→      entityId: toRecordIdString(row.out),
759→      entityKind,
760→      entityName,
761→      confidence: row.confidence,
762→      extractedAt: toIso(row.extracted_at),
763→    });
764→  }
765→
766→  return results;
767→}
