771→async function readEntityNameByTable(
772→  surreal: Surreal,
773→  record: RecordId<string, string>,
774→  table: string,
775→): Promise<string | undefined> {
776→  if (table === "workspace" || table === "project" || table === "person" || table === "feature") {
777→    const row = await surreal.select<{ name: string }>(record);
778→    return row?.name;
779→  }
780→
781→  if (table === "task") {
782→    const row = await surreal.select<{ title: string }>(record);
783→    return row?.title;
784→  }
785→
786→  if (table === "decision") {
787→    const row = await surreal.select<{ summary: string }>(record);
788→    return row?.summary;
789→  }
790→
791→  if (table === "question") {
792→    const row = await surreal.select<{ text: string }>(record);
793→    return row?.text;
794→  }
795→
796→  return undefined;
797→}
