  1→import { RecordId } from "surrealdb";
  2→import { ENTITY_PRIORITIES, type EntityActionRequest } from "../../shared/contracts";
  3→import { HttpError } from "../http/errors";
  4→import { logError, logInfo } from "../http/observability";
  5→import { jsonError, jsonResponse } from "../http/response";
  6→import { acknowledgeObservation, resolveObservation } from "../observation/queries";
  7→import type { ServerDependencies } from "../runtime/types";
  8→import { resolveWorkspaceRecord } from "../workspace/workspace-scope";
  9→import {
 10→  confirmDecisionRecord,
 11→  isEntityInWorkspace,
 12→  parseRecordIdString,
 13→  type GraphEntityTable,
 14→} from "../graph/queries";
 15→import { fireDescriptionUpdates } from "../descriptions/triggers";
 16→
 17→type EntityActionTable = GraphEntityTable | "observation";
 18→
 19→export function createEntityActionsHandler(
 20→  deps: ServerDependencies,
 21→): (entityId: string, request: Request) => Promise<Response> {
 22→  return (entityId: string, request: Request) => handleEntityAction(deps, entityId, request);
 23→}
 24→
 25→async function handleEntityAction(
 26→  deps: ServerDependencies,
 27→  entityId: string,
 28→  request: Request,
 29→): Promise<Response> {
 30→  let body: EntityActionRequest;
 31→  try {
 32→    body = await request.json() as EntityActionRequest;
 33→  } catch {
 34→    return jsonError("invalid JSON body", 400);
 35→  }
 36→
 37→  if (!body.action || !["confirm", "override", "complete", "set_priority", "acknowledge", "resolve"].includes(body.action)) {
 38→    return jsonError("action must be one of: confirm, override, complete, set_priority, acknowledge, resolve", 400);
 39→  }
 40→
 41→  const url = new URL(request.url);
 42→  const workspaceId = url.searchParams.get("workspaceId")?.trim();
 43→  if (!workspaceId) {
 44→    return jsonError("workspaceId is required", 400);
 45→  }
 46→
 47→  let workspaceRecord;
 48→  try {
 49→    workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
 50→  } catch (error) {
 51→    if (error instanceof HttpError) {
 52→      return jsonError(error.message, error.status);
 53→    }
 54→    logError("entity.action.workspace_resolve.failed", "Failed to resolve workspace", error, { workspaceId });
 55→    return jsonError("failed to resolve workspace", 500);
 56→  }
 57→
 58→  try {
 59→    const entityTables: EntityActionTable[] = ["workspace", "project", "person", "feature", "task", "decision", "question", "observation"];
 60→    const entityRecord = parseRecordIdString(entityId, entityTables);
 61→
 62→    const table = entityRecord.table.name;
 63→    const now = new Date();
 64→
 65→    // Observation actions bypass the standard workspace scope check
 66→    // because observations have their own workspace field (not graph edges).
 67→    if (table === "observation") {
 68→      if (body.action === "acknowledge") {
 69→        await acknowledgeObservation({
 70→          surreal: deps.surreal,
 71→          workspaceRecord,
 72→          observationRecord: entityRecord as RecordId<"observation", string>,
 73→          now,
 74→        });
 75→        logInfo("entity.action.acknowledge", "Observation acknowledged", { workspaceId, entityId });
 76→        return jsonResponse({ status: "acknowledged" }, 200);
 77→      }
 78→
