```typescript
import { type RecordId, type Surreal } from "surrealdb";
import { logInfo, logWarn } from "../http/observability";

type OrphanRow = {
  id: RecordId<string, string>;
  source_message?: RecordId<"message", string>;
  source_commit?: RecordId<"git_commit", string>;
};

export async function backfillEntityWorkspaces(surreal: Surreal): Promise<void> {
  for (const table of ["task", "decision", "question"] as const) {
    const [orphans] = await surreal
      .query<[OrphanRow[]]>(
        `SELECT id, source_message, source_commit FROM ${table} WHERE workspace = NONE;`,
      )
      .collect<[OrphanRow[]]>();

    if (orphans.length === 0) continue;
    logInfo("backfill.workspace.start", `Backfilling workspace for ${orphans.length} ${table} records`, { table, count: orphans.length });

    let resolved = 0;
    for (const row of orphans) {
      // Path 1: source_message -> conversation -> workspace
      if (row.source_message) {
        const [ws] = await surreal
          .query<[Array<RecordId<"workspace", string>>]>(
            "SELECT VALUE workspace FROM conversation WHERE id = (SELECT VALUE conversation FROM $msg LIMIT 1) LIMIT 1;",
            { msg: row.source_message },
          )
          .collect<[Array<RecordId<"workspace", string>>]>();
        if (ws[0]) {
          await surreal.update(row.id).merge({ workspace: ws[0] });
          resolved++;
          continue;
        }
      }

      // Path 2: source_commit -> git_commit.workspace
      if (row.source_commit) {
        const [ws] = await surreal
          .query<[Array<RecordId<"workspace", string>>]>(
            "SELECT VALUE workspace FROM git_commit WHERE id = $commit LIMIT 1;",
            { commit: row.source_commit },
          )
          .collect<[Array<RecordId<"workspace", string>>]>();
        if (ws[0]) {
          await surreal.update(row.id).merge({ workspace: ws[0] });
          resolved++;
          continue;
        }
      }

      // Path 3: belongs_to -> project -> has_project -> workspace
      const [ws] = await surreal
        .query<[Array<RecordId<"workspace", string>>]>(
          "SELECT VALUE `in` FROM has_project WHERE out IN (SELECT VALUE out FROM belongs_to WHERE `in` = $entity) LIMIT 1;",
          { entity: row.id },
        )
        .collect<[Array<RecordId<"workspace", string>>]>();
      if (ws[0]) {
        await surreal.update(row.id).merge({ workspace: ws[0] });
        resolved++;
        continue;
      }

      logWarn("backfill.workspace.unresolved", `Could not resolve workspace for ${table}:${row.id.id as string}`, { table, id: row.id.id as string });
    }

    logInfo("backfill.workspace.done", `Backfilled ${resolved}/${orphans.length} ${table} records`, { table, resolved, total: orphans.length });
  }
}
```

